use crate::ast_types::*;

fn render_node_ref(node_id: &str, label: &str) -> String {
    format!("({}:{})", node_id, label)
}

fn render_node_spec(node_id: &str, label: &str) -> String {
    format!("{}:{}", node_id, label)
}

pub fn render_topology_source(
    export_name: &str,
    node_plans: &[BridgeNodePlan],
    operations: &[BridgeOperation],
) -> String {
    let mut lines = vec![
        format!("// ts-bridge.gg — generated from exported TypeScript function '{}'", export_name),
    ];

    let entry_plan = &node_plans[0]; // Assumes node_plans[0] is Entry
    let mut current_node_id = entry_plan.node_id().to_string();
    let mut current_label = entry_plan.handler_label().to_string();

    for operation in operations {
        match operation {
            BridgeOperation::Parallel { branches, join_plan } => {
                let branch_refs: Vec<String> = branches.iter()
                    .map(|p| render_node_spec(p.node_id(), p.handler_label()))
                    .collect();
                
                lines.push(format!("{}-[:FORK]->({})", 
                    render_node_ref(&current_node_id, &current_label),
                    branch_refs.join(" | ")
                ));

                let branch_ids: Vec<String> = branches.iter()
                    .map(|p| p.node_id().to_string())
                    .collect();

                lines.push(format!("({})-[:FOLD]->{}",
                    branch_ids.join(" | "),
                    render_node_ref(join_plan.node_id(), join_plan.handler_label())
                ));

                current_node_id = join_plan.node_id().to_string();
                current_label = join_plan.handler_label().to_string();
            }
            BridgeOperation::Assign { plan } | BridgeOperation::Call { plan } | BridgeOperation::Return { plan } => {
                lines.push(format!("{}-[:PROCESS]->{}",
                    render_node_ref(&current_node_id, &current_label),
                    render_node_ref(plan.node_id(), plan.handler_label())
                ));
                current_node_id = plan.node_id().to_string();
                current_label = plan.handler_label().to_string();
            }
        }
    }

    let mut output = lines.join("\n");
    output.push('\n');
    output
}

pub fn build_bridge_ast(
    node_plans: &[BridgeNodePlan],
    operations: &[BridgeOperation],
) -> GraphAST {
    let mut nodes = Vec::new();
    let mut edges = Vec::new();

    let create_node = |id: &str, label: &str| -> ASTNode {
        ASTNode {
            id: id.to_string(),
            labels: vec![label.to_string()],
            properties: serde_json::Value::Object(serde_json::Map::new()),
        }
    };

    let create_edge = |sources: Vec<String>, targets: Vec<String>, edge_type: &str| -> ASTEdge {
        ASTEdge {
            source_ids: sources,
            target_ids: targets,
            r#type: edge_type.to_string(),
            properties: serde_json::Value::Object(serde_json::Map::new()),
        }
    };

    // nodes in node_plans order matches TS state.nodePlans.map(...)
    for plan in node_plans {
        nodes.push(create_node(plan.node_id(), plan.handler_label()));
    }

    // edges in operations order
    let mut current_node_id = if let Some(plan) = node_plans.first() {
        plan.node_id().to_string()
    } else {
        String::new()
    };

    for operation in operations {
        match operation {
            BridgeOperation::Parallel { branches, join_plan } => {
                let mut branch_ids = Vec::new();
                for branch in branches {
                    if let BridgeNodePlan::Call { node_id, .. } = branch {
                        branch_ids.push(node_id.clone());
                    }
                }

                edges.push(create_edge(vec![current_node_id.clone()], branch_ids.clone(), "FORK"));

                if let BridgeNodePlan::Join { node_id, .. } = join_plan {
                    edges.push(create_edge(branch_ids, vec![node_id.clone()], "FOLD"));
                    current_node_id = node_id.clone();
                }
            }
            BridgeOperation::Assign { plan } => {
                let node_id = plan.node_id();
                edges.push(create_edge(vec![current_node_id.clone()], vec![node_id.to_string()], "PROCESS"));
                current_node_id = node_id.to_string();
            }
            BridgeOperation::Call { plan } => {
                let node_id = plan.node_id();
                edges.push(create_edge(vec![current_node_id.clone()], vec![node_id.to_string()], "PROCESS"));
                current_node_id = node_id.to_string();
            }
            BridgeOperation::Return { plan } => {
                let node_id = plan.node_id();
                edges.push(create_edge(vec![current_node_id.clone()], vec![node_id.to_string()], "PROCESS"));
                current_node_id = node_id.to_string();
            }
        }
    }

    GraphAST {
        nodes,
        edges,
    }
}

pub fn build_schedule(operations: &[BridgeOperation]) -> Vec<BridgeWave> {
    let mut schedule = Vec::new();
    let mut wave_index = 0;

    for operation in operations {
        match operation {
            BridgeOperation::Parallel { branches, join_plan } => {
                let mut node_ids = Vec::new();
                for branch in branches {
                    if let BridgeNodePlan::Call { node_id, .. } = branch {
                        node_ids.push(node_id.clone());
                    }
                }
                schedule.push(BridgeWave {
                    index: wave_index,
                    kind: "parallel".to_string(),
                    node_ids,
                });
                wave_index += 1;

                if let BridgeNodePlan::Join { node_id, .. } = join_plan {
                    schedule.push(BridgeWave {
                        index: wave_index,
                        kind: "collapse".to_string(),
                        node_ids: vec![node_id.clone()],
                    });
                    wave_index += 1;
                }
            }
            BridgeOperation::Assign { plan } => {
                if let BridgeNodePlan::Assign { node_id, .. } = plan {
                    schedule.push(BridgeWave {
                        index: wave_index,
                        kind: "linear".to_string(),
                        node_ids: vec![node_id.clone()],
                    });
                    wave_index += 1;
                }
            }
            BridgeOperation::Call { plan } => {
                if let BridgeNodePlan::Call { node_id, .. } = plan {
                    schedule.push(BridgeWave {
                        index: wave_index,
                        kind: "linear".to_string(),
                        node_ids: vec![node_id.clone()],
                    });
                    wave_index += 1;
                }
            }
            BridgeOperation::Return { plan } => {
                if let BridgeNodePlan::Return { node_id, .. } = plan {
                    schedule.push(BridgeWave {
                        index: wave_index,
                        kind: "linear".to_string(),
                        node_ids: vec![node_id.clone()],
                    });
                    wave_index += 1;
                }
            }
        }
    }

    schedule
}
